import{_ as d,o as e,c as i,a2 as a}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"LEARN-link audit (May 2026)","description":"","frontmatter":{},"headers":[],"relativePath":"research/learn-link-audit.md","filePath":"research/learn-link-audit.md"}'),o={name:"research/learn-link-audit.md"};function r(s,t,n,l,c,g){return e(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="learn-link-audit-may-2026" tabindex="-1">LEARN-link audit (May 2026) <a class="header-anchor" href="#learn-link-audit-may-2026" aria-label="Permalink to &quot;LEARN-link audit (May 2026)&quot;">​</a></h1><p>Inventory of every external link reachable from a detail-panel <strong>LEARN</strong> tab in the production app. The audit is the planning baseline for ADR-051 and the v0.5.0 LEARN-link stewardship rollout (epic <a href="https://github.com/chipi/orrery/issues/51" target="_blank" rel="noreferrer">#51</a>).</p><h2 id="methodology" tabindex="-1">Methodology <a class="header-anchor" href="#methodology" aria-label="Permalink to &quot;Methodology&quot;">​</a></h2><p>A walker over every JSON file under <code>static/data/</code> (excluding <code>schemas/</code>, <code>porkchop/</code>, and the i18n overlay tree) collects every value of:</p><ul><li>the structured <code>links: [{ l, u, t }]</code> arrays (per <code>src/types/mission.ts</code>, <code>src/types/iss-module.ts</code>, <code>src/types/earth-object.ts</code>, <code>src/types/surface-site.ts</code>, <code>src/types/sun.ts</code>, <code>src/types/planet.ts</code>, <code>src/types/rocket.ts</code>)</li><li>the single-string <code>wiki</code> field on <code>static/data/small-bodies.json</code></li></ul><p>Result: <strong>925 outbound link entries</strong> across the production data.</p><h2 id="distribution-by-host" tabindex="-1">Distribution by host <a class="header-anchor" href="#distribution-by-host" aria-label="Permalink to &quot;Distribution by host&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Rank</th><th>Host</th><th style="text-align:right;">Count</th><th style="text-align:right;">Share</th></tr></thead><tbody><tr><td style="text-align:right;">1</td><td>en.wikipedia.org</td><td style="text-align:right;">351</td><td style="text-align:right;">38 %</td></tr><tr><td style="text-align:right;">2</td><td>science.nasa.gov</td><td style="text-align:right;">209</td><td style="text-align:right;">23 %</td></tr><tr><td style="text-align:right;">3</td><td>nasa.gov</td><td style="text-align:right;">47</td><td style="text-align:right;">5 %</td></tr><tr><td style="text-align:right;">4</td><td>nature.com</td><td style="text-align:right;">43</td><td style="text-align:right;">5 %</td></tr><tr><td style="text-align:right;">5</td><td>science.org</td><td style="text-align:right;">31</td><td style="text-align:right;">3 %</td></tr><tr><td style="text-align:right;">6</td><td>voyager.jpl.nasa.gov</td><td style="text-align:right;">28</td><td style="text-align:right;">3 %</td></tr><tr><td style="text-align:right;">7</td><td>esa.int</td><td style="text-align:right;">25</td><td style="text-align:right;">3 %</td></tr><tr><td style="text-align:right;">8</td><td>mars.nasa.gov</td><td style="text-align:right;">15</td><td style="text-align:right;">2 %</td></tr><tr><td style="text-align:right;">9</td><td>sciencedirect.com</td><td style="text-align:right;">15</td><td style="text-align:right;">2 %</td></tr><tr><td style="text-align:right;">10</td><td>eospso.nasa.gov</td><td style="text-align:right;">14</td><td style="text-align:right;">2 %</td></tr><tr><td style="text-align:right;">11</td><td>climatekids.nasa.gov</td><td style="text-align:right;">14</td><td style="text-align:right;">2 %</td></tr><tr><td style="text-align:right;">12</td><td>planetary.org</td><td style="text-align:right;">14</td><td style="text-align:right;">2 %</td></tr><tr><td style="text-align:right;">13</td><td>nap.nationalacademies.org</td><td style="text-align:right;">14</td><td style="text-align:right;">2 %</td></tr><tr><td style="text-align:right;">14</td><td>iopscience.iop.org</td><td style="text-align:right;">14</td><td style="text-align:right;">2 %</td></tr><tr><td style="text-align:right;">15</td><td>sdo.gsfc.nasa.gov</td><td style="text-align:right;">14</td><td style="text-align:right;">2 %</td></tr><tr><td style="text-align:right;">16</td><td>annualreviews.org</td><td style="text-align:right;">14</td><td style="text-align:right;">2 %</td></tr><tr><td style="text-align:right;">17</td><td>es.wikipedia.org</td><td style="text-align:right;">13</td><td style="text-align:right;">1 %</td></tr><tr><td style="text-align:right;">18</td><td>nssdc.gsfc.nasa.gov</td><td style="text-align:right;">11</td><td style="text-align:right;">1 %</td></tr><tr><td style="text-align:right;">19</td><td>spacex.com</td><td style="text-align:right;">6</td><td style="text-align:right;">1 %</td></tr><tr><td style="text-align:right;">20</td><td>isro.gov.in</td><td style="text-align:right;">5</td><td style="text-align:right;">1 %</td></tr><tr><td style="text-align:right;">21</td><td>cosmos.esa.int</td><td style="text-align:right;">2</td><td style="text-align:right;">&lt; 1 %</td></tr><tr><td style="text-align:right;">22</td><td>lroc.asu.edu</td><td style="text-align:right;">2</td><td style="text-align:right;">&lt; 1 %</td></tr><tr><td style="text-align:right;">23</td><td>humans-in-space.jaxa.jp</td><td style="text-align:right;">2</td><td style="text-align:right;">&lt; 1 %</td></tr><tr><td style="text-align:right;">24</td><td>mbrsc.ae</td><td style="text-align:right;">2</td><td style="text-align:right;">&lt; 1 %</td></tr><tr><td style="text-align:right;">25</td><td>global.jaxa.jp</td><td style="text-align:right;">2</td><td style="text-align:right;">&lt; 1 %</td></tr></tbody></table><p>NASA-domain hosts together account for ~37 %. Wikipedia (en + es) accounts for ~39 %. Together: 76 % of every outbound LEARN link.</p><h2 id="distribution-by-data-category" tabindex="-1">Distribution by data category <a class="header-anchor" href="#distribution-by-data-category" aria-label="Permalink to &quot;Distribution by data category&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th style="text-align:right;">Links</th></tr></thead><tbody><tr><td><code>static/data/planets/**</code></td><td style="text-align:right;">560</td></tr><tr><td><code>static/data/missions/**</code></td><td style="text-align:right;">86</td></tr><tr><td><code>static/data/sun.json</code></td><td style="text-align:right;">70</td></tr><tr><td><code>static/data/mars-sites.json</code></td><td style="text-align:right;">50</td></tr><tr><td><code>static/data/earth-objects.json</code></td><td style="text-align:right;">40</td></tr><tr><td><code>static/data/moon-sites.json</code></td><td style="text-align:right;">38</td></tr><tr><td><code>static/data/iss-modules.json</code></td><td style="text-align:right;">34</td></tr><tr><td><code>static/data/rockets.json</code></td><td style="text-align:right;">22</td></tr><tr><td><code>static/data/iss-visitors.json</code></td><td style="text-align:right;">17</td></tr><tr><td><code>static/data/small-bodies.json</code> (<code>wiki</code> field)</td><td style="text-align:right;">8</td></tr></tbody></table><p>Planets are the largest contributor (560 links) but the gap analysis below shows the highest-leverage editorial enrichment is on missions, earth-objects, and the ISS Russian-segment modules.</p><h2 id="distribution-by-tier" tabindex="-1">Distribution by tier <a class="header-anchor" href="#distribution-by-tier" aria-label="Permalink to &quot;Distribution by tier&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Links</th><th style="text-align:right;">Share</th></tr></thead><tbody><tr><td><code>intro</code></td><td style="text-align:right;">445</td><td style="text-align:right;">48 %</td></tr><tr><td><code>core</code></td><td style="text-align:right;">339</td><td style="text-align:right;">37 %</td></tr><tr><td><code>deep</code></td><td style="text-align:right;">141</td><td style="text-align:right;">15 %</td></tr></tbody></table><p>ADR-051 will use this distribution to set the build-fail policy: <code>intro</code> and <code>core</code> 4xx/5xx fail validation; <code>deep</code> soft-warns.</p><h2 id="non-us-agency-footprint" tabindex="-1">Non-US agency footprint <a class="header-anchor" href="#non-us-agency-footprint" aria-label="Permalink to &quot;Non-US agency footprint&quot;">​</a></h2><p>The total share of outbound links going to non-US agency hosts today:</p><table tabindex="0"><thead><tr><th>Host</th><th style="text-align:right;">Count</th></tr></thead><tbody><tr><td>esa.int</td><td style="text-align:right;">25</td></tr><tr><td>isro.gov.in</td><td style="text-align:right;">5</td></tr><tr><td>cosmos.esa.int</td><td style="text-align:right;">2</td></tr><tr><td>humans-in-space.jaxa.jp</td><td style="text-align:right;">2</td></tr><tr><td>mbrsc.ae</td><td style="text-align:right;">2</td></tr><tr><td>global.jaxa.jp</td><td style="text-align:right;">2</td></tr></tbody></table><p><strong>Total: 38 of 925 = 4.1 %.</strong></p><p><code>roscosmos.ru</code> appears once across the entire data set (on <code>iss-visitors.json:soyuz_ms</code>). <code>cnsa.gov.cn</code> appears zero times despite Chang&#39;e and Tianwen-1 being in the mission library. JAXA&#39;s mission-specific microsites (<code>mmx.jaxa.jp</code>, <code>global.jaxa.jp</code>) each appear once for the JAXA-led missions but the agency root is missing for several other entities.</p><h2 id="non-english-footprint" tabindex="-1">Non-English footprint <a class="header-anchor" href="#non-english-footprint" aria-label="Permalink to &quot;Non-English footprint&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Language</th><th>Source</th><th style="text-align:right;">Count</th></tr></thead><tbody><tr><td>en</td><td>(every other host)</td><td style="text-align:right;">911</td></tr><tr><td>es</td><td>es.wikipedia.org</td><td style="text-align:right;">13</td></tr><tr><td>(unspecified)</td><td>other Spanish-language pages</td><td style="text-align:right;">1</td></tr></tbody></table><p>Zero links to native-language pages on Roscosmos, CNSA, JAXA-jp, or ISRO-hi despite obvious primary sources existing for non-US missions. ADR-051 corrects this with the locale fallback chain.</p><h2 id="per-mission-gap-list-wikipedia-only-or-operator-portal-missing" tabindex="-1">Per-mission gap list (Wikipedia-only or operator-portal-missing) <a class="header-anchor" href="#per-mission-gap-list-wikipedia-only-or-operator-portal-missing" aria-label="Permalink to &quot;Per-mission gap list (Wikipedia-only or operator-portal-missing)&quot;">​</a></h2><p>The missions below either have only Wikipedia as a source or are missing the operating-agency portal. ADR-051 / Milestone L-C must add the agency portal as the <em>first</em> <code>intro</code> link.</p><table tabindex="0"><thead><tr><th>Mission</th><th>Operator</th><th>Today</th><th>Gap</th></tr></thead><tbody><tr><td><code>change5</code></td><td>CNSA</td><td>en.wikipedia.org × 1</td><td>No CNSA portal, no native-language link</td></tr><tr><td><code>change6</code></td><td>CNSA</td><td>en.wikipedia.org × 1</td><td>No CNSA portal, no native-language link</td></tr><tr><td><code>chandrayaan3</code></td><td>ISRO</td><td>en.wikipedia.org × 1</td><td>No ISRO portal, no native-language link</td></tr><tr><td><code>tianwen1</code></td><td>CNSA</td><td>en.wikipedia.org × 2</td><td>No CNSA portal, no native-language link</td></tr><tr><td><code>change4</code></td><td>CNSA</td><td>en.wikipedia.org × 2</td><td>No CNSA portal</td></tr><tr><td><code>chandrayaan1</code></td><td>ISRO</td><td>en.wikipedia.org, science.org</td><td>No ISRO portal</td></tr><tr><td><code>mangalyaan</code></td><td>ISRO</td><td>en.wikipedia.org, isro.gov.in</td><td>Missing Hindi-language ISRO equivalent</td></tr><tr><td><code>slim</code></td><td>JAXA</td><td>en.wikipedia.org, global.jaxa.jp</td><td>Missing Japanese-language JAXA equivalent</td></tr><tr><td><code>mars-express</code></td><td>ESA</td><td>en.wikipedia.org, esa.int</td><td>OK; consider adding national-language ESA pages</td></tr><tr><td><code>hope-probe</code></td><td>UAESA</td><td>en.wikipedia.org, mbrsc.ae</td><td>OK</td></tr><tr><td><code>mmx</code></td><td>JAXA</td><td>en.wikipedia.org, mmx.jaxa.jp, sciencedirect</td><td>OK</td></tr><tr><td><code>luna9</code> / <code>luna17</code> / <code>luna24</code></td><td>Roscosmos / Soviet</td><td>Wikipedia + NASA NSSDC + publishers</td><td>No Roscosmos portal, no Russian-language link</td></tr><tr><td><code>mars3</code></td><td>Soviet / Roscosmos</td><td>Wikipedia + NASA NSSDC + nasa.gov</td><td>No Roscosmos portal</td></tr><tr><td><code>starship-demo</code> / <code>starship-mars-crew</code></td><td>SpaceX</td><td>spacex.com + Wikipedia</td><td>OK</td></tr></tbody></table><h2 id="per-entity-gap-list-earth-objects" tabindex="-1">Per-entity gap list (earth-objects) <a class="header-anchor" href="#per-entity-gap-list-earth-objects" aria-label="Permalink to &quot;Per-entity gap list (earth-objects)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Entity</th><th>Operator</th><th>Today</th><th>Gap</th></tr></thead><tbody><tr><td><code>beidou</code></td><td>CNSA</td><td>en.wikipedia.org × 1</td><td>No CNSA portal, no <code>en.beidou.gov.cn</code></td></tr><tr><td><code>glonass</code></td><td>Roscosmos</td><td>en.wikipedia.org × 1</td><td>No <code>glonass-iac.ru</code></td></tr><tr><td><code>tiangong</code></td><td>CNSA</td><td>Wikipedia × 2</td><td>No CNSA portal</td></tr><tr><td><code>chandrayaan1</code> (orbiter view)</td><td>ISRO</td><td>en.wikipedia.org × 1</td><td>No ISRO portal</td></tr><tr><td><code>change1</code> / <code>change2</code></td><td>CNSA</td><td>en.wikipedia.org × 1 each</td><td>No CNSA portal</td></tr><tr><td><code>clementine</code></td><td>NASA / DoD</td><td>en.wikipedia.org × 1</td><td>OK</td></tr><tr><td><code>lunar-prospector</code></td><td>NASA</td><td>en.wikipedia.org × 1</td><td>OK; add NASA mission page</td></tr><tr><td><code>smart-1</code></td><td>ESA</td><td>en.wikipedia.org × 1</td><td>Add <code>sci.esa.int/web/smart-1/</code></td></tr><tr><td><code>gaia</code></td><td>ESA</td><td>en.wikipedia.org, cosmos.esa.int</td><td>OK</td></tr><tr><td><code>xmm</code></td><td>ESA</td><td>en.wikipedia.org, cosmos.esa.int</td><td>OK</td></tr><tr><td><code>galileo</code></td><td>ESA</td><td>en.wikipedia.org, esa.int</td><td>OK</td></tr><tr><td><code>hubble</code></td><td>NASA / ESA</td><td>Wikipedia, hubblesite.org, nasa.gov</td><td>Add <code>esahubble.org</code></td></tr><tr><td><code>jwst</code></td><td>NASA / ESA / CSA</td><td>Wikipedia, webbtelescope.org, stsci.edu</td><td>OK; consider adding CSA + ESA pages</td></tr><tr><td><code>iss</code></td><td>NASA et al.</td><td>Wikipedia, spotthestation, nasa.gov</td><td>OK</td></tr><tr><td><code>chandra</code></td><td>NASA</td><td>Wikipedia, chandra.harvard.edu</td><td>OK</td></tr><tr><td><code>lro</code></td><td>NASA</td><td>Wikipedia, lroc.asu.edu</td><td>OK</td></tr><tr><td><code>geo</code></td><td>NOAA</td><td>Wikipedia, goes.noaa.gov</td><td>OK</td></tr><tr><td><code>gps</code></td><td>US Space Force</td><td>Wikipedia, gps.gov</td><td>OK</td></tr><tr><td><code>luna10</code></td><td>Roscosmos / Soviet</td><td>en.wikipedia.org × 1</td><td>No Roscosmos portal</td></tr></tbody></table><h2 id="iss-module-visitor-gap-list" tabindex="-1">ISS module + visitor gap list <a class="header-anchor" href="#iss-module-visitor-gap-list" aria-label="Permalink to &quot;ISS module + visitor gap list&quot;">​</a></h2><p>ISS Russian-segment modules link to <code>roscosmos.ru</code> only on <code>soyuz_ms</code> today. Other Russian-segment modules and visitors miss the operator portal:</p><table tabindex="0"><thead><tr><th>Module</th><th>Operator</th><th>Today</th><th>Gap</th></tr></thead><tbody><tr><td><code>zarya</code></td><td>Roscosmos</td><td>Wikipedia, nasa.gov</td><td>Add <code>roscosmos.ru</code> and Energia builder page</td></tr><tr><td><code>zvezda</code></td><td>Roscosmos</td><td>Wikipedia, nasa.gov</td><td>Add <code>roscosmos.ru</code></td></tr><tr><td><code>nauka</code></td><td>Roscosmos</td><td>Wikipedia, nasa.gov</td><td>Add <code>roscosmos.ru</code></td></tr><tr><td><code>pirs</code></td><td>Roscosmos</td><td>Wikipedia, nasa.gov</td><td>Add <code>roscosmos.ru</code></td></tr><tr><td><code>prichal</code></td><td>Roscosmos</td><td>Wikipedia, nasa.gov</td><td>Add <code>roscosmos.ru</code></td></tr><tr><td><code>rassvet</code></td><td>Roscosmos</td><td>Wikipedia, nasa.gov</td><td>Add <code>roscosmos.ru</code></td></tr><tr><td><code>progress_ms</code></td><td>Roscosmos</td><td>Wikipedia, nasa.gov</td><td>Add <code>roscosmos.ru</code></td></tr><tr><td><code>columbus</code></td><td>ESA</td><td>Wikipedia, esa.int</td><td>OK</td></tr><tr><td><code>kibo</code></td><td>JAXA</td><td>Wikipedia, humans-in-space.jaxa.jp</td><td>OK; consider adding Japanese-language equivalent</td></tr><tr><td><code>htv_x</code></td><td>JAXA</td><td>Wikipedia, humans-in-space.jaxa.jp</td><td>OK</td></tr><tr><td><code>canadarm2</code></td><td>CSA</td><td>Wikipedia, asc-csa.gc.ca</td><td>OK</td></tr><tr><td><code>crew_dragon</code></td><td>NASA / SpaceX</td><td>Wikipedia, nasa.gov, spacex.com</td><td>OK</td></tr><tr><td><code>starliner</code></td><td>NASA / Boeing</td><td>Wikipedia, nasa.gov, boeing.com</td><td>OK</td></tr></tbody></table><h2 id="site-level-gap-list" tabindex="-1">Site-level gap list <a class="header-anchor" href="#site-level-gap-list" aria-label="Permalink to &quot;Site-level gap list&quot;">​</a></h2><p>Lunar and Mars surface sites are mission landings — they should reference the operating agency&#39;s mission page even when the rover is decades old:</p><table tabindex="0"><thead><tr><th>Site category</th><th>Gap</th></tr></thead><tbody><tr><td><code>moon-sites/luna-*</code></td><td>Most have only Wikipedia; add Roscosmos / Lavochkin builder pages where extant</td></tr><tr><td><code>moon-sites/change-*</code></td><td>Add CNSA portal links (zh + en) for each landing</td></tr><tr><td><code>moon-sites/chandrayaan-3</code></td><td>Add ISRO mission page (en + hi if available)</td></tr><tr><td><code>moon-sites/slim</code></td><td>Add JAXA SLIM page (en + ja)</td></tr><tr><td><code>moon-sites/hakuto-r</code></td><td>Add ispace mission page (en + ja)</td></tr><tr><td><code>moon-sites/smart-1</code></td><td>Add ESA SMART-1 page</td></tr><tr><td><code>mars-sites/*</code> for non-NASA landers</td><td>Apply the same agency-first rule when expanding the catalogue</td></tr></tbody></table><h2 id="what-adr-051-must-lock" tabindex="-1">What ADR-051 must lock <a class="header-anchor" href="#what-adr-051-must-lock" aria-label="Permalink to &quot;What ADR-051 must lock&quot;">​</a></h2><p>The audit motivates the contract:</p><ol><li><strong>Source diversity targets</strong> — non-US entities must have their operating agency portal as the <em>first</em> <code>intro</code> link; no entity may link only to Wikipedia.</li><li><strong>Per-link metadata</strong> — every link gets a TASL-equivalent provenance row (URL, label, source, language, kind, last-verified, fair-use rationale, replaced-with).</li><li><strong>Locale fallback chain</strong> — UI locale → operator native language → English.</li><li><strong>Rendering rules</strong> — <code>rel=&quot;noopener noreferrer external&quot;</code>, <code>hreflang</code>, tracker-stripping, no AMP variants.</li><li><strong>Public disclosure</strong> — the <code>/library</code> page lists every outbound link grouped by source, newest-verified first.</li><li><strong>Build-fail policy</strong> — broken <code>intro</code> / <code>core</code> links fail <code>validate-data</code>; <code>deep</code> soft-warns.</li></ol><p>ADR-051 is the lock; Milestones L-B / L-C / L-D / L-E carry it into code, data, UI, and tooling.</p>',38)])])}const y=d(o,[["render",r]]);export{p as __pageData,y as default};
